// Create a recursive function to create the nested generic type
function nestedType<T>(type: T) {
    if (type === 'number' || type === 'string') {
        return type + '[]';
    } else {
        return type + '[]';
    }
}

// Test the function
console.log(nestedType('number')); // Output: number[]
console.log(nestedType('string')); // Output: string[]

