class Solution:
    def nestedType(self, type: str) -> str:
        if type in ['number', 'string']:
            return type + '[]'
        else:
            return type + '[]'

# Test the function
solution = Solution()
print(solution.nestedType('number')) # Output: number[]
print(solution.nestedType('string')) # Output: string[]
